test('todo app works', async ({ page }) => {
  // Add todo
  await page.getByPlaceholder(/add|new|todo/i).fill('Buy groceries');
  await page.keyboard.press('Enter');
  await expect(page.getByText('Buy groceries')).toBeVisible();

  // Add another
  await page.getByPlaceholder(/add|new|todo/i).fill('Walk the dog');
  await page.keyboard.press('Enter');
  await expect(page.getByText('Walk the dog')).toBeVisible();

  // Complete first todo
  const firstCheckbox = page.locator('input[type=checkbox]').first();
  await firstCheckbox.check();

  // Filter to active
  await page.getByRole('button', { name: /active/i }).click();
  await expect(page.getByText('Walk the dog')).toBeVisible();

  // Filter to completed
  await page.getByRole('button', { name: /completed/i }).click();
  await expect(page.getByText('Buy groceries')).toBeVisible();

  // Delete
  await page.getByText('Buy groceries').hover();
  const deleteBtn = page.locator('button').filter({ hasText: /delete|remove|×|✕/ }).first();
  if (await deleteBtn.isVisible()) await deleteBtn.click();
});
